Mashup.mashupContent:
{ "CustomMashupCss" : ".noOverflow > div {
 overflow: hidden !important;
}

.noOverflow ptcs-value-display {
 overflow: hidden !important;
}

.BMCollectionViewCellWrapper {
 width: 100% !important;
}
/* hide the enlarge button in value display */
/*ptcs-value-display::part(disclosure-button-overlay) {
 visibility: hidden !important;
 display: none !important;
}
div#disclosurebuttonoverlay {
 visibility: hidden !important;
 display: none !important;
}*/
/* hide the enlarge button in value display */
ptcs-value-display {
 overflow-option: none !important;
}
/* Parameter column width */
.parameterCustom ptcs-value-display::part(item-value)::part(root) {
 max-width: 184px !important;
}
.parameterCustom ptcs-value-display::part(overflow-control) {
 max-width: 200px !important;
 overflow: inherit;
 /*margin-top: 8px !important;*/
}
.parameterCustom ptcs-value-display::part(disclosure-button-overlay) {
 visibility: hidden !important;
 display: none !important;
}
/* Machine column width */
.machineCustom ptcs-value-display::part(item-value)::part(root) {
 max-width: 234px !important;
}
.machineCustom ptcs-value-display::part(overflow-control) {
 max-width: 250px !important;
 overflow: inherit;
 /*margin-top: 8px !important;*/
}
.machineCustom ptcs-value-display::part(disclosure-button-overlay) {
 visibility: hidden !important;
 display: none !important;
}
/* Location column width */
.locationCustom ptcs-value-display::part(item-value)::part(root) {
 max-width: 129px !important;
}
.locationCustom ptcs-value-display::part(overflow-control) {
 max-width: 145px !important;
 overflow: inherit;
 /*margin-top: 8px !important;*/
}
.locationCustom ptcs-value-display::part(disclosure-button-overlay) {
 visibility: hidden !important;
 display: none !important;
}
/* Description column width */
.descriptionCustom ptcs-value-display::part(item-value)::part(root) {
 max-width: 435px !important;
}
.descriptionCustom ptcs-value-display::part(overflow-control) {
 max-width: 451px !important;
 overflow: inherit;
 /*margin-top: 8px !important;*/
}
.descriptionCustom ptcs-value-display::part(disclosure-button-overlay) {
 visibility: hidden !important;
 display: none !important;
}
/* Checkbox */
ptcs-checkbox {
 zoom: 150% !important;
 padding: 0px !important;
 translate: 10px !important;
}


